32	    generic (
33	        Width_g       : positive
34	    );
35	    port (
36	        In_Clk      : in    std_logic;
37	        In_RstIn    : in    std_logic;
38	        In_RstOut   : out   std_logic;
39	        In_Valid    : in    std_logic;
40	        In_Ready    : out   std_logic;
41	        In_Data     : in    std_logic_vector(Width_g - 1 downto 0);
42	        Out_Clk     : in    std_logic;
43	        Out_RstIn   : in    std_logic := '0';
44	        Out_RstOut  : out   std_logic;
45	        Out_Valid   : out   std_logic;
46	        Out_Ready   : in    std_logic := '1';
47	        Out_Data    : out   std_logic_vector(Width_g - 1 downto 0)
48	    );
49	end entity;
50	
51	architecture rtl of olo_base_cc_xn2n is
52	
53	    -- Input Side
54	    signal InCnt         : unsigned(1 downto 0);
55	    signal InRstInt      : std_logic;
56	    signal InDataReg     : std_logic_vector(Width_g - 1 downto 0);
57	    signal InDataRegLast : std_logic_vector(Width_g - 1 downto 0);
58	
59	    -- Output Side
60	    signal OutCnt      : unsigned(1 downto 0);
61	    signal OutRstInt   : std_logic;
62	    signal OutIn_Valid : std_logic;
63	
64	begin
65	
66	    In_Ready <= '1' when (InCnt - OutCnt /= 2) and (InRstInt = '0') else '0';
67	
68	    p_input : process (In_Clk) is
69	    begin
70	        if rising_edge(In_Clk) then
71	            if In_Valid = '1' and InCnt - OutCnt /= 2 then
72	                InCnt         <= InCnt + 1;
73	                InDataReg     <= In_Data;
74	                InDataRegLast <= InDataReg;
75	            end if;
76	            -- Reset
77	            if InRstInt = '1' then
78	                InCnt <= (others => '0');
79	            end if;
80	        end if;
81	    end process;
82	
83	    p_output : process (Out_Clk) is
84	    begin
85	        if rising_edge(Out_Clk) then
86	            -- New sample was acknowledged
87	            if OutIn_Valid = '1' and Out_Ready = '1' then
88	                OutIn_Valid <= '0';
89	            end if;
90	            -- Forward new sample to output if ready
91	            if InCnt /= OutCnt and (OutIn_Valid = '0' or Out_Ready = '1') then
92	                if InCnt - OutCnt = 1 then
93	                    Out_Data <= InDataReg;
94	                else
95	                    Out_Data <= InDataRegLast;
96	                end if;
97	                OutIn_Valid <= '1';
98	                OutCnt      <= OutCnt + 1;
99	            end if;
100	            if OutRstInt = '1' then
101	                OutCnt      <= (others => '0');
102	                OutIn_Valid <= '0';
103	            end if;
104	        end if;
105	    end process;
106	
107	    Out_Valid <= OutIn_Valid;
108	
109	    -- *** Reset Crossing ***
110	    i_rst_cc : entity work.olo_base_cc_reset
111	        port map (
112	            A_Clk       => In_Clk,
113	            A_RstIn     => In_RstIn,
114	            A_RstOut    => InRstInt,
115	            B_Clk       => Out_Clk,
116	            B_RstIn     => Out_RstIn,
117	            B_RstOut    => OutRstInt
118	        );
119	
120	    In_RstOut  <= InRstInt;
121	    Out_RstOut <= OutRstInt;
122	
123	end architecture;
